function SettingsPage() {
    const buttonStyle = {
    width: "100%",
    textAlign: "left",
    padding: "8px 10px",
    borderBottom: "1px solid #ccc",
    background: "white",
    cursor: "pointer",
  };

  const buttonHover = {
    backgroundColor: "#f5f5f5",
  };



  return (
    <div>
      <div
      className="settings-table"
    >
      {/* Левая панель */}
      <div
        style={{
          width: "250px",
          borderRight: "1px solid #ccc",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          padding: "16px",
        }}
      >
        {/* Аватар */}
        <div
          style={{
            width: "100px",
            height: "100px",
            backgroundColor: "#ccc",
            borderRadius: "50%",
            marginBottom: "8px",
          }}
        ></div>
        <span style={{ fontSize: "14px", color: "#333", marginBottom: "16px" }}>
          Name
        </span>

        {/* Меню */}
        <div style={{ width: "100%", fontSize: "14px" }}>
          <button style={buttonStyle}>Просмотр профиля</button>
          <button style={buttonStyle}>Профиль</button>
          <button style={buttonStyle}>Фото</button>
          <button style={buttonStyle}>Безопасность</button>
          <button style={buttonStyle}>Text</button>
          <button style={{ ...buttonStyle, color: "red" }}>Выйти</button>
        </div>
      </div>

      {/* Правая часть контента */}
      <div style={{ flex: 1, padding: "16px" }}>
        {/* Контент справа */}
      </div>
    </div>
    </div>
  );
}

export default SettingsPage;
